def sanitize_sensitive_data(data):
    """Sanitize sensitive information from logs"""
    if not isinstance(data, dict):
        return data
    
    sanitized = data.copy()
    sensitive_fields = ['password', 'token', 'api_key', 'secret', 'authorization', 
                       'credit_card', 'ssn', 'auth_token', 'access_token']
    
    for key in sanitized:
        if any(sensitive in key.lower() for sensitive in sensitive_fields):
            sanitized[key] = '***REDACTED***'
        elif isinstance(sanitized[key], dict):
            sanitized[key] = sanitize_sensitive_data(sanitized[key])
    
    return sanitized


def log_request():
    """Log incoming request details with sanitized sensitive data"""
    request_data = {
        'timestamp': datetime.utcnow().isoformat(),
        'method': request.method,
        'path': request.path,
        'remote_addr': request.remote_addr,
        'user_agent': str(request.user_agent),
        'headers': dict(request.headers),
        'args': dict(request.args),
    }
    
    if request.is_json:
        try:
            request_data['body'] = request.get_json()
        except:
            request_data['body'] = None
    elif request.form:
        request_data['form'] = dict(request.form)
    
    sanitized_data = sanitize_sensitive_data(request_data)
    app.logger.info(f"REQUEST: {json.dumps(sanitized_data, indent=2)}")


def log_response(response):
    """Log outgoing response details"""
    response_data = {
        'timestamp': datetime.utcnow().isoformat(),
        'status_code': response.status_code,
        'headers': dict(response.headers),
    }
    
    try:
        if response.is_json:
            response_data['body'] = response.get_json()
    except:
        pass
    
    sanitized_data = sanitize_sensitive_data(response_data)
    app.logger.info(f"RESPONSE: {json.dumps(sanitized_data, indent=2)}")
    return response


@app.before_request
def before_request():
    """Execute before each request"""
    g.start_time = datetime.utcnow()
    log_request()


@app.after_request
def after_request(response):
    """Execute after each request"""
    if hasattr(g, 'start_time'):
        elapsed = (datetime.utcnow() - g.start_time).total_seconds()
        app.logger.info(f"Request completed in {elapsed:.3f} seconds")
    
    return log_response(response)


def require_auth(f):
    """Authentication decorator with sanitized logging"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        
        if not auth_header:
            app.logger.warning(f"Authentication failed: No authorization header provided from {request.remote_addr}")
            return jsonify({'error': 'No authorization header'}), 401
        
        # In production, NEVER log actual tokens - this is sanitized
        app.logger.info(f"Authentication attempt from {request.remote_addr} with token: ***REDACTED***")
        
        # Simulate token validation
        if auth_header != 'Bearer valid-token':
            app.logger.warning(f"Authentication failed: Invalid token from {request.remote_addr}")
            return jsonify({'error': 'Invalid token'}), 401
        
        app.logger.info(f"Authentication successful for {request.remote_addr}")
        return f(*args, **kwargs)
    
    return decorated_function


@app.errorhandler(Exception)
def handle_exception(e):
    """Global exception handler with detailed logging"""
    error_data = {
        'timestamp': datetime.utcnow().isoformat(),
        'error_type': type(e).__name__,
        'error_message': str(e),
        'path': request.path,
        'method': request.method,
        'remote_addr': request.remote_addr,
        'traceback': traceback.format_exc()
    }
    
    app.logger.error(f"EXCEPTION: {json.dumps(error_data, indent=2)}")
    
    return jsonify({
        'error': 'Internal server error',
        'message': str(e)
    }), 500


